app.Run();

public class FileUploadResult
{
    public bool Success { get; set; }
    public string? FilePath { get; set; }
    public string? FileName { get; set; }
    public long FileSize { get; set; }
    public string? ContentType { get; set; }
    public string? ErrorMessage { get; set; }
}

public class MultipleFileUploadResult
{
    public bool Success { get; set; }
    public List<FileUploadResult> Files { get; set; } = new();
    public int TotalUploaded { get; set; }
    public int TotalFailed { get; set; }
}

[ApiController]
[Route("api/[controller]")]
public class FileUploadController : ControllerBase
{
    private readonly IWebHostEnvironment _environment;

    private static readonly HashSet<string> AllowedAvatarExtensions = new(StringComparer.OrdinalIgnoreCase)
    {
        ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp", ".svg"
    };

    private static readonly HashSet<string> AllowedDocumentExtensions = new(StringComparer.OrdinalIgnoreCase)
    {
        ".pdf",
        ".doc", ".docx",
        ".xls", ".xlsx",
        ".ppt", ".pptx",
        ".txt", ".csv",
        ".rtf", ".odt", ".ods", ".odp"
    };

    private static readonly HashSet<string> AllowedAvatarContentTypes = new(StringComparer.OrdinalIgnoreCase)
    {
        "image/jpeg", "image/png", "image/gif", "image/bmp", "image/webp", "image/svg+xml"
    };

    private static readonly HashSet<string> AllowedDocumentContentTypes = new(StringComparer.OrdinalIgnoreCase)
    {
        "application/pdf",
        "application/msword",
        "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
        "application/vnd.ms-excel",
        "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        "application/vnd.ms-powerpoint",
        "application/vnd.openxmlformats-officedocument.presentationml.presentation",
        "text/plain",
        "text/csv",
        "application/rtf",
        "application/vnd.oasis.opendocument.text",
        "application/vnd.oasis.opendocument.spreadsheet",
        "application/vnd.oasis.opendocument.presentation"
    };

    private const long MaxAvatarSize = 5 * 1024 * 1024; // 5 MB
    private const long MaxDocumentSize = 50 * 1024 * 1024; // 50 MB

    public FileUploadController(IWebHostEnvironment environment)
    {
        _environment = environment;
    }

    [HttpPost("avatar")]
    [RequestSizeLimit(5 * 1024 * 1024)]
    public async Task<ActionResult<FileUploadResult>> UploadAvatar(IFormFile file)
    {
        if (file == null || file.Length == 0)
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = "No file provided or file is empty."
            });
        }

        var validationError = ValidateFile(file, AllowedAvatarExtensions, AllowedAvatarContentTypes, MaxAvatarSize, "avatar");
        if (validationError != null)
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = validationError
            });
        }

        var result = await SaveFileAsync(file, "avatars");
        if (!result.Success)
        {
            return StatusCode(500, result);
        }

        return Ok(result);
    }

    [HttpPost("document")]
    [RequestSizeLimit(50 * 1024 * 1024)]
    public async Task<ActionResult<FileUploadResult>> UploadDocument(IFormFile file)
    {
        if (file == null || file.Length == 0)
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = "No file provided or file is empty."
            });
        }

        var validationError = ValidateFile(file, AllowedDocumentExtensions, AllowedDocumentContentTypes, MaxDocumentSize, "document");
        if (validationError != null)
        {
            return BadRequest(new FileUploadResult
            {
                Success = false,
                ErrorMessage = validationError
            });
        }

        var result = await SaveFileAsync(file, "documents");
        if (!result.Success)
        {
            return StatusCode(500, result);
        }

        return Ok(result);
    }

    [HttpPost("documents")]
    [RequestSizeLimit(200 * 1024 * 1024)]
    public async Task<ActionResult<MultipleFileUploadResult>> UploadMultipleDocuments(List<IFormFile> files)
    {
        if (files == null || files.Count == 0)
        {
            return BadRequest(new MultipleFileUploadResult
            {
                Success = false,
                Files = new List<FileUploadResult>
                {
                    new() { Success = false, ErrorMessage = "No files provided." }
                }
            });
        }

        var multiResult = new MultipleFileUploadResult();

        foreach (var file in files)
        {
            if (file.Length == 0)
            {
                multiResult.Files.Add(new FileUploadResult
                {
                    Success = false,
                    FileName = file.FileName,
                    ErrorMessage = "File is empty."
                });
                multiResult.TotalFailed++;
                continue;
            }

            var validationError = ValidateFile(file, AllowedDocumentExtensions, AllowedDocumentContentTypes, MaxDocumentSize, "document");
            if (validationError != null)
            {
                multiResult.Files.Add(new FileUploadResult
                {
                    Success = false,
                    FileName = file.FileName,
                    ErrorMessage = validationError
                });
                multiResult.TotalFailed++;
                continue;
            }

            var result = await SaveFileAsync(file, "documents");
            multiResult.Files.Add(result);

            if (result.Success)
                multiResult.TotalUploaded++;
            else
                multiResult.TotalFailed++;
        }

        multiResult.Success = multiResult.TotalFailed == 0;

        return Ok(multiResult);
    }

    private string? ValidateFile(IFormFile file, HashSet<string> allowedExtensions, HashSet<string> allowedContentTypes, long maxSize, string fileType)
    {
        var extension = Path.GetExtension(file.FileName);

        if (string.IsNullOrEmpty(extension) || !allowedExtensions.Contains(extension))
        {
            return $"File type '{extension}' is not allowed for {fileType} uploads. Allowed types: {string.Join(", ", allowedExtensions)}";
        }

        if (!allowedContentTypes.Contains(file.ContentType))
        {
            return $"Content type '{file.ContentType}' is not allowed for {fileType} uploads.";
        }

        if (file.Length > maxSize)
        {
            return $"File size ({file.Length / (1024 * 1024.0):F2} MB) exceeds the maximum allowed size ({maxSize / (1024 * 1024)} MB) for {fileType} uploads.";
        }

        var fileName = Path.GetFileNameWithoutExtension(file.FileName);
        if (string.IsNullOrWhiteSpace(fileName))
        {
            return "Invalid file name.";
        }

        var invalidChars = Path.GetInvalidFileNameChars();
        if (file.FileName.Any(c => invalidChars.Contains(c)))
        {
            return "File name contains invalid characters.";
        }

        return null;
    }

    private async Task<FileUploadResult> SaveFileAsync(IFormFile file, string subfolder)
    {
        try
        {
            var uploadsRoot = Path.Combine(_environment.WebRootPath, "uploads", subfolder);

            if (!Directory.Exists(uploadsRoot))
            {
                Directory.CreateDirectory(uploadsRoot);
            }

            var extension = Path.GetExtension(file.FileName);
            var uniqueFileName = $"{Guid.NewGuid():N}{extension}";
            var filePath = Path.Combine(uploadsRoot, uniqueFileName);

            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                await file.CopyToAsync(stream);
            }

            var relativePath = Path.Combine("uploads", subfolder, uniqueFileName).Replace("\\", "/");

            return new FileUploadResult
            {
                Success = true,
                FilePath = $"/{relativePath}",
                FileName = uniqueFileName,
                FileSize = file.Length,
                ContentType = file.ContentType
            };
        }
        catch (Exception ex)
        {
            return new FileUploadResult
            {
                Success = false,
                FileName = file.FileName,
                ErrorMessage = $"An error occurred while saving the file: {ex.Message}"
            };
        }
    }
}